.small {
  font-size: $type-size-6;
}

.cv-list {
  margin: 0 0 1.5em;
}

.cv-item {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 1rem;
  margin: 0 0 1rem;
  padding-bottom: 1rem;
  border-bottom: 1px solid $border-color;
}

.cv-item__main p:last-child {
  margin-bottom: 0;
}

.cv-item__date {
  color: mix(#fff, $text-color, 35%);
  font-family: $sans-serif-narrow;
  font-size: $type-size-6;
  line-height: 1.5;
  text-align: right;
  white-space: nowrap;
}

@include breakpoint(max-width $small) {
  .cv-item {
    display: block;
  }

  .cv-item__date {
    margin-top: 0.25rem;
    text-align: left;
  }
}

